// MARK: - Secure Token Storage (Keychain)

final class TokenStore {
    static let shared = TokenStore()
    
    private let accessTokenKey = "com.example.app.accessToken"
    private let refreshTokenKey = "com.example.app.refreshToken"
    
    private init() {}
    
    var accessToken: String? {
        get { readKeychain(key: accessTokenKey) }
        set {
            if let value = newValue {
                saveKeychain(key: accessTokenKey, value: value)
            } else {
                deleteKeychain(key: accessTokenKey)
            }
        }
    }
    
    var refreshToken: String? {
        get { readKeychain(key: refreshTokenKey) }
        set {
            if let value = newValue {
                saveKeychain(key: refreshTokenKey, value: value)
            } else {
                deleteKeychain(key: refreshTokenKey)
            }
        }
    }
    
    func clearAll() {
        accessToken = nil
        refreshToken = nil
    }
    
    // MARK: - Keychain Helpers
    
    private func saveKeychain(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        
        var addQuery = query
        addQuery[kSecValueData as String] = data
        
        SecItemAdd(addQuery as CFDictionary, nil)
    }
    
    private func readKeychain(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        
        return String(data: data, encoding: .utf8)
    }
    
    private func deleteKeychain(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Certificate Pinner (SSL Pinning Delegate)

final class CertificatePinningDelegate: NSObject, URLSessionDelegate {
    
    private let environment: Environment
    
    init(environment: Environment) {
        self.environment = environment
        super.init()
    }
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // 1. Verify the hostname matches what we expect
        let host = challenge.protectionSpace.host
        guard host == environment.expectedHostname else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // 2. Perform standard TLS validation first
        let policy = SecPolicyCreateSSL(true, host as CFString)
        SecTrustSetPolicies(serverTrust, policy)
        
        var error: CFError?
        guard SecTrustEvaluateWithError(serverTrust, &error) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // 3. Certificate pinning: check SPKI hash of the leaf certificate
        guard let serverCertificate = SecTrustGetCertificateAtIndex(serverTrust, 0) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        guard let serverPublicKey = SecCertificateCopyKey(serverCertificate),
              let serverPublicKeyData = SecKeyCopyExternalRepresentation(serverPublicKey, nil) as Data? else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let serverPinHash = sha256Hash(data: serverPublicKeyData)
        let pinnedHashes = environment.pinnedCertificateHashes
        
        if pinnedHashes.contains(serverPinHash) {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else {
            // Pin mismatch — reject the connection
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
    
    private func sha256Hash(data: Data) -> String {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes { buffer in
            _ = CC_SHA256(buffer.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash).base64EncodedString()
    }
}

