// MARK: - Network Client

final class NetworkClient {
    
    static let shared = NetworkClient()
    
    private let environment: Environment
    private let session: URLSession
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    private let pinningDelegate: CertificatePinningDelegate
    
    private var isRefreshing = false
    private var refreshQueue: [(Result<String, NetworkError>) -> Void] = []
    private let refreshLock = NSLock()
    
    init(environment: Environment = .production) {
        self.environment = environment
        self.pinningDelegate = CertificatePinningDelegate(environment: environment)
        
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        configuration.httpAdditionalHeaders = [
            "Accept": "application/json",
            "Content-Type": "application/json"
        ]
        // Enforce TLS 1.2 minimum
        configuration.tlsMinimumSupportedProtocolVersion = .TLSv12
        
        // Use the pinning delegate for all connections
        self.session = URLSession(
            configuration: configuration,
            delegate: pinningDelegate,
            delegateQueue: nil
        )
        
        self.decoder = JSONDecoder()
        self.encoder = JSONEncoder()
    }
    
    // MARK: - Generic Request
    
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable? = nil,
        queryItems: [URLQueryItem]? = nil,
        responseType: T.Type,
        completion: @escaping (Result<T, NetworkError>) -> Void
    ) {
        guard var urlComponents = URLComponents(string: environment.baseURL + endpoint.path) else {
            completion(.failure(.invalidURL))
            return
        }
        
        urlComponents.queryItems = queryItems
        
        guard let url = urlComponents.url else {
            completion(.failure(.invalidURL))
            return
        }
        
        // Enforce HTTPS
        guard url.scheme == "https" else {
            completion(.failure(.invalidURL))
            return
        }
        
        var urlRequest = URLRequest(url: url)
        urlRequest.httpMethod = endpoint.method.rawValue
        urlRequest.cachePolicy = .reloadIgnoringLocalCacheData
        
        if let body = body {
            do {
                urlRequest.httpBody = try encoder.encode(body)
            } catch {
                completion(.failure(.decodingError(error)))
                return
            }
        }
        
        if endpoint.requiresAuth {
            guard let token = TokenStore.shared.accessToken else {
                completion(.failure(.unauthorized))
                return
            }
            urlRequest.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        let task = session.dataTask(with: urlRequest) { [weak self] data, response, error in
            guard let self = self else { return }
            
            if let error = error {
                // Check if this was a pinning failure
                let nsError = error as NSError
                if nsError.domain == NSURLErrorDomain &&
                    (nsError.code == NSURLErrorServerCertificateUntrusted ||
                     nsError.code == NSURLErrorServerCertificateHasBadDate ||
                     nsError.code == NSURLErrorServerCertificateHasUnknownRoot ||
                     nsError.code == NSURLErrorServerCertificateNotYetValid ||
                     nsError.code == NSURLErrorCancelled) {
                    DispatchQueue.main.async {
                        completion(.failure(.certificatePinningFailed))
                    }
                    return
                }
                DispatchQueue.main.async {
                    completion(.failure(.networkFailure(error)))
                }
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                DispatchQueue.main.async {
                    completion(.failure(.invalidResponse))
                }
                return
            }
            
            // Handle 401 with token refresh
            if httpResponse.statusCode == 401 && endpoint.requiresAuth && endpoint != .refreshToken {
                self.handleTokenRefresh { result in
                    switch result {
                    case .success:
                        // Retry the original request
                        self.request(
                            endpoint: endpoint,
                            body: body,
                            queryItems: queryItems,
                            responseType: responseType,
                            completion: completion
                        )
                    case .failure(let error):
                        DispatchQueue.main.async {
                            completion(.failure(error))
                        }
                    }
                }
                return
            }
            
            guard (200...299).contains(httpResponse.statusCode) else {
                let message = self.parseErrorMessage(from: data)
                let error: NetworkError = httpResponse.statusCode == 401
                    ? .unauthorized
                    : .serverError(statusCode: httpResponse.statusCode, message: message)
                DispatchQueue.main.async {
                    completion(.failure(error))
                }
                return
            }
            
            guard let data = data else {
                DispatchQueue.main.async {
                    completion(.failure(.noData))
                }
                return
            }
            
            do {
                let decoded = try self.decoder.decode(T.self, from: data)
                DispatchQueue.main.async {
                    completion(.success(decoded))
                }
            } catch {
                DispatchQueue.main.async {
                    completion(.failure(.decodingError(error)))
                }
            }
        }
        
        task.resume()
    }
    
    // MARK: - Token Refresh
    
    private func handleTokenRefresh(completion: @escaping (Result<String, NetworkError>) -> Void) {
        refreshLock.lock()
        
        refreshQueue.append(completion)
        
        if isRefreshing {
            refreshLock.unlock()
            return
        }
        
        isRefreshing = true
        refreshLock.unlock()
        
        guard let refreshToken = TokenStore.shared.refreshToken else {
            finishRefresh(with: .failure(.unauthorized))
            return
        }
        
        let body = RefreshTokenRequest(refreshToken: refreshToken)
        
        request(endpoint: .refreshToken, body: body, responseType: AuthResponse.self) { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success(let authResponse):
                TokenStore.shared.accessToken = authResponse.accessToken
                TokenStore.shared.refreshToken = authResponse.refreshToken
                self.finishRefresh(with: .success(authResponse.accessToken))
            case .failure:
                TokenStore.shared.clearAll()
                self.finishRefresh(with: .failure(.unauthorized))
            }
        }
    }
    
    private func finishRefresh(with result: Result<String, NetworkError>) {
        refreshLock.lock()
        let queue = refreshQueue
        refreshQueue.removeAll()
        isRefreshing = false
        refreshLock.unlock()
        
        for completion in queue {
            completion(result)
        }
    }
    
    // MARK: - Helpers
    
    private func parseErrorMessage(from data: Data?) -> String? {
        guard let data = data else { return nil }
        return try? decoder.decode(APIErrorResponse.self, from: data).message
    }
    
    // Equatable check for endpoint (used in 401 guard)
    // We compare by path to avoid infinite refresh loops
}

extension APIEndpoint: Equatable {
    static func == (lhs: APIEndpoint, rhs: APIEndpoint) -> Bool {
        return lhs.path == rhs.path && lhs.method == rhs.method
    }
}

extension HTTPMethod: Equatable {}

// MARK: - API Service (High-Level Convenience)

final class APIService {
    
    private let client: NetworkClient
    
    init(client: NetworkClient = .shared) {
        self.client = client
    }
    
    // MARK: - Authentication
    
    func login(email: String, password: String, completion: @escaping (Result<User, NetworkError>) -> Void) {
        let body = AuthRequest(email: email, password: password)
        
        client.request(endpoint: .login, body: body, responseType: AuthResponse.self) { result in
            switch result {
            case .success(let authResponse):
                TokenStore.shared.accessToken = authResponse.accessToken
                TokenStore.shared.refreshToken = authResponse.refreshToken
                completion(.success(authResponse.user))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func register(email: String, password: String, completion: @escaping (Result<User, NetworkError>) -> Void) {
        let body = AuthRequest(email: email, password: password)
        
        client.request(endpoint: .register, body: body, responseType: AuthResponse.self) { result in
            switch result {
            case .success(let authResponse):
                TokenStore.shared.accessToken = authResponse.accessToken
                TokenStore.shared.refreshToken = authResponse.refreshToken
                completion(.success(authResponse.user))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func logout() {
        TokenStore.shared.clearAll()
    }
    
    // MARK: - User Data
    
    func fetchCurrentUser(completion: @escaping (Result<User, NetworkError>) -> Void) {
        client.request(endpoint: .userProfile, responseType: User.self, completion: completion)
    }
    
    func fetchUsers(completion: @escaping (Result<[User], NetworkError>) -> Void) {
        client.request(endpoint: .users, responseType: [User].self, completion: completion)
    }
}

